var e=[{id:`L2_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`어이쿠! 빈틈입니다!`,JPN:`おっと！　隙あり！`,ENG:`Oopsie! I see an opening!`,TWN:`嘿！有破綻！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`으랏챠!`,JPN:`よっしゃー！`,ENG:`Alley-oop!`,TWN:`哎喲！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`일부러 보여 준 건데 설렜나 봐?`,JPN:`わざとチラ見せしたけど、ときめいちゃった？`,ENG:`That was intentional. Were you excited?`,TWN:`我是故意露出破綻的啦，你心動了嗎？`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`......그거 아세요? 당신 말투 정말 거슬리네요.`,JPN:`……わかってます？　あなたの喋り方、ホント気に障るんですよ。`,ENG:`Do you know how annoying you sound when you talk?`,TWN:`……妳知道嗎？妳的語氣真的很煩人呢。`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`자주 듣던 말인가 보네, 오빠? 이런 게 자기반성이라는 걸까?`,JPN:`お兄ちゃんも身に覚えがあるとか？　反省してるのかな？`,ENG:`Why, have you heard that often, big brother? This is what people call self-reflection, isn't it?`,TWN:`這話我很常聽到呢，哥。這算是自我反省嗎？`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`전 별로 반성할 게 없는 인생을 살아왔는데, 그쪽은 아닌가 보네요.`,JPN:`僕にはあまり反省すべきことなんてないですが、そっちは違うみたいですね。`,ENG:`I haven't done anything that requires me to reflect on myself. Have you?`,TWN:`我的人生沒什麼需要反省的東西，妳看起來倒是有挺多的。`},stage:{bg:`COUNTRYROAD`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`바로 그런 점이 반성해야 할 부분이 아닐까, 동생?`,JPN:`まさにそういうところを改めるべきじゃないの、弟くん？`,ENG:`Shouldn't you reflect on yourself about that, little brother?`,TWN:`你需要反省的不就是這一點嗎，弟弟？`},stage:{bg:`COUNTRYROAD`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`동생인지 오빠인지 하나만 하시죠!!`,JPN:`弟なのか兄なのか、どっちかに絞ってくれませんかね！！`,ENG:`Am I your older or little brother? Make up your mind!`,TWN:`到底是弟弟還是哥哥啦！！`},stage:{bg:`COUNTRYROAD`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`글쎄, 꼭 그래야 하나? 난 욕심쟁이라서 둘 다 하고 싶은데.`,JPN:`ふーん、そんな必要ある？　私は欲張りだから、両方がいいな。`,ENG:`Should I? I'm greedy. I want both.`,TWN:`唉，一定得分清楚嗎？我很貪心不能全都要嗎？`},stage:{bg:`COUNTRYROAD`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_PRIDE`}}}},{id:`L23_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`......더는 못 들어주겠군.`,JPN:`……聞いてられんな。`,ENG:`Argh, I can't take this anymore.`,TWN:`……我聽不下去了。`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`주시윤, 비켜.`,JPN:`シリュウ、どけ。`,ENG:`Shiyoon, move aside.`,TWN:`周時雲，走開。`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`하하, 이번엔 그쪽 차례인가요? 제법 기대되는......`,JPN:`ハハ、今度はそっちの番？　こりゃ、楽しみだ……`,ENG:`Hah hah. Is it going to be you this time? I can't wait—`,TWN:`哈哈，這次輪到妳了嗎？我很期待……`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`크흣!`,JPN:`くっ！`,ENG:`Ugh!`,TWN:`唔噗！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`임기응변에 능한 걸 보면 실전 경험이 꽤 많은가 보군.`,JPN:`臨機応変に動けるのは実戦の経験が豊富だからだろうな。`,ENG:`You must be a veteran soldier, being so good at improvising.`,TWN:`臨場反應不錯，看來妳的戰鬥經驗非常豐富。`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};